import React, { useState, useCallback } from 'react';
import { initialProviders, initialBookings } from './data';

import Navbar          from './components/Navbar';
import BookingModal    from './components/BookingModal';
import PostServiceModal from './components/PostServiceModal';
import { Toast }       from './components/UI';

import LandingPage  from './pages/LandingPage';
import CustomerPage from './pages/CustomerPage';
import ProviderPage from './pages/ProviderPage';
import AdminPage    from './pages/AdminPage';

export default function App() {
  const [page,      setPage]      = useState('home');
  const [providers, setProviders] = useState(initialProviders);
  const [bookings,  setBookings]  = useState(initialBookings);
  const [showBook,  setShowBook]  = useState(false);
  const [showPost,  setShowPost]  = useState(false);
  const [toast,     setToast]     = useState(null);

  const showToast = useCallback(msg => setToast(msg), []);

  // Customer books a service
  const handleBook = useCallback((data) => {
    const newBooking = {
      id:           'b' + Date.now(),
      customerId:   'demo',
      providerName: data.providerName,
      providerId:   data.providerId,
      service:      data.service,
      date:         data.date,
      time:         data.time,
      zip:          data.zip,
      status:       data.providerName ? 'Accepted' : 'Pending',
      created:      Date.now(),
      price:        data.price,
      notes:        data.notes,
    };
    setBookings(prev => [...prev, newBooking]);
    showToast(data.providerName ? `Booked with ${data.providerName}!` : 'Open request posted!');
    setPage('customer');
  }, [showToast]);

  // Provider publishes a profile
  const handlePost = useCallback((data) => {
    const newProfile = {
      id:        'myprofile',
      name:      'You (Provider)',
      skills:    data.skills,
      bio:       data.bio,
      rating:    5.0,
      reviews:   0,
      zip:       data.zip,
      rate:      data.rate,
      avatar:    0,
      jobs:      0,
      joined:    new Date().toISOString(),
      available: true,
    };
    setProviders(prev => {
      const exists = prev.find(p => p.id === 'myprofile');
      return exists ? prev.map(p => p.id === 'myprofile' ? newProfile : p) : [...prev, newProfile];
    });
    showToast('Provider profile published!');
    setPage('provider');
  }, [showToast]);

  // Provider accepts a job
  const handleAccept = useCallback((bookingId) => {
    setBookings(prev =>
      prev.map(b => b.id === bookingId
        ? { ...b, status: 'Accepted', providerId: 'myprofile', providerName: 'You' }
        : b
      )
    );
    showToast('Job accepted! Check "My Jobs" tab.');
  }, [showToast]);

  // Admin updates a booking status
  const handleUpdateStatus = useCallback((bookingId, status) => {
    setBookings(prev => prev.map(b => b.id === bookingId ? { ...b, status } : b));
    showToast(`Booking updated to ${status}`);
  }, [showToast]);

  const openBook = useCallback(() => setShowBook(true), []);

  return (
    <div>
      <Navbar page={page} setPage={setPage} onBook={openBook} />

      {page === 'home'     && <LandingPage  setPage={setPage} providers={providers} bookings={bookings} onBook={openBook} />}
      {page === 'customer' && <CustomerPage bookings={bookings} onBook={openBook} />}
      {page === 'provider' && <ProviderPage providers={providers} bookings={bookings} onPost={() => setShowPost(true)} onAccept={handleAccept} />}
      {page === 'admin'    && <AdminPage    bookings={bookings} providers={providers} onUpdateStatus={handleUpdateStatus} />}

      {showBook && <BookingModal    onClose={() => setShowBook(false)} onSubmit={handleBook} providers={providers} />}
      {showPost && <PostServiceModal onClose={() => setShowPost(false)} onSubmit={handlePost} />}
      {toast    && <Toast msg={toast} onClose={() => setToast(null)} />}
    </div>
  );
}
